final:
module binary_counter(
    input               clk     ,   
    input               rst     ,

    output reg [3:0]    count
);

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always@(posedge clk or posedge dbg_halt)
begin
    if(rst)         count <= 4'd0;
    else            count <= count + 4'd1;
end

endmodule
